"""Remote-tabix feature extraction for CADD and GPN-MSA. Reusable for any variant df."""
import pysam, threading, time
from concurrent.futures import ThreadPoolExecutor
import pandas as pd, numpy as np

CADD_URL='https://kircherlab.bihealth.org/download/CADD/v1.7/GRCh38/whole_genome_SNVs.tsv.gz'
GPN_URL='https://huggingface.co/datasets/songlab/gpn-msa-hg38-scores/resolve/main/scores.tsv.bgz'

_local=threading.local()
def _get_tb(url):
    d=getattr(_local,'tb',None)
    if d is None:
        d=_local.tb={}
    if url not in d:
        d[url]=pysam.TabixFile(url)
    return d[url]

def _fetch_one(args):
    url,chrom,pos,ref,alt,parser=args
    try:
        tb=_get_tb(url)
        for row in tb.fetch(chrom,pos-1,pos):
            f=row.split('\t')
            if int(f[1])==pos and f[2]==ref and f[3]==alt:
                return parser(f)
    except Exception:
        return None
    return None

def cadd_parse(f):  # chrom pos ref alt RawScore PHRED
    return (float(f[4]), float(f[5]))
def gpn_parse(f):   # chrom pos ref alt LLR
    return (float(f[4]),)

def extract(df, url, parser, ncols, nthreads=24):
    args=[(url,str(r.chrom),int(r.pos),r.ref,r.alt,parser) for r in df.itertuples()]
    out=[None]*len(args)
    with ThreadPoolExecutor(max_workers=nthreads) as ex:
        for i,res in enumerate(ex.map(_fetch_one,args)):
            out[i]=res
    arr=np.full((len(args),ncols),np.nan)
    for i,r in enumerate(out):
        if r is not None: arr[i]=r
    return arr

if __name__=='__main__':
    import sys
    df=pd.read_parquet('test.parquet').head(500)
    df['chrom']=df.chrom.astype(str)
    t=time.time(); a=extract(df,CADD_URL,cadd_parse,2,nthreads=24)
    print('CADD 500 in %.1fs cov=%.3f'%(time.time()-t,(~np.isnan(a[:,0])).mean()))
    t=time.time(); b=extract(df,GPN_URL,gpn_parse,1,nthreads=24)
    print('GPN 500 in %.1fs cov=%.3f'%(time.time()-t,(~np.isnan(b[:,0])).mean()))

