                    return parser(f)
            return None  # found region but no matching allele
        except Exception:
            time.sleep(0.3*(attempt+1))
    return None

def cadd_parse(f): return (float(f[4]), float(f[5]))   # RawScore, PHRED
def gpn_parse(f):  return (float(f[4]),)                # LLR

