"""Local feature extraction: bigWig conservation + AlphaMissense tabix + GPN-MSA local tabix."""
import pyBigWig, pysam, numpy as np, pandas as pd, threading, time
from concurrent.futures import ThreadPoolExecutor

BW={'phyloP241':'data/phyloP241.bw','phyloP100':'data/phyloP100.bw','phastCons100':'data/phastCons100.bw'}
AM='data/AlphaMissense_hg38.tsv.gz'
GPN_LOCAL='data/gpn_scores.tsv.bgz'

def bigwig_features(df):
    out={k:np.full(len(df),np.nan) for k in BW}
    chroms=df.chrom.astype(str).values; pos=df.pos.values.astype(int)
    for k,path in BW.items():
        bw=pyBigWig.open(path)
        valid=set(bw.chroms().keys())
        for i in range(len(df)):
            c='chr'+chroms[i]
            if c not in valid: continue
            try:
                v=bw.values(c,pos[i]-1,pos[i])[0]
                if v==v: out[k][i]=v
            except Exception: pass
        bw.close()
    return pd.DataFrame(out)

_l=threading.local()
def _am_one(args):
    chrom,pos,ref,alt=args
    tb=getattr(_l,'am',None)
    if tb is None: tb=_l.am=pysam.TabixFile(AM)
    best=np.nan
    try:
        for row in tb.fetch('chr'+chrom,pos-1,pos):
            f=row.split('\t')
            if int(f[1])==pos and f[2]==ref and f[3]==alt:
                v=float(f[8])
                if not (best==best) or v>best: best=v
    except Exception: pass
    return best

def am_features(df,nthreads=16):
    args=[(str(r.chrom),int(r.pos),r.ref,r.alt) for r in df.itertuples()]
    out=np.full(len(df),np.nan)
    with ThreadPoolExecutor(max_workers=nthreads) as ex:
        for i,v in enumerate(ex.map(_am_one,args)): out[i]=v
    return out

_g=threading.local()
def _gpn_one(args):
    chrom,pos,ref,alt=args
    tb=getattr(_g,'g',None)
    if tb is None: tb=_g.g=pysam.TabixFile(GPN_LOCAL)
    try:
        for row in tb.fetch(chrom,pos-1,pos):
            f=row.split('\t')
            if int(f[1])==pos and f[2]==ref and f[3]==alt:
                return float(f[4])
    except Exception: pass
    return np.nan

def gpn_local(df,nthreads=16):
    args=[(str(r.chrom),int(r.pos),r.ref,r.alt) for r in df.itertuples()]
    out=np.full(len(df),np.nan)
    with ThreadPoolExecutor(max_workers=nthreads) as ex:
        for i,v in enumerate(ex.map(_gpn_one,args)): out[i]=v
    return out

